class Solution {
public:
    bool isSubsequence(string s, string t) {
        int m = t.length();
        int n = s.length();

        vector<int> dp(m + 1, 0);

        for (int i = 0; i < m; i++) {
            for (int j = 0; j <= n; j++) {
                if (t[i] == s[j]) {
                    dp[i + 1] = dp[i] + 1;
                }
            }
        }

        return dp[n];
    }
};
```

